# Production-grade agent with safeguards (cricket match simulation)
import time
from typing import Dict, List

class CricketAgentWithSafeguards:
    def __init__(self, team_name: str, max_iterations: int = 50, timeout_sec: int = 30):
        self.team_name = team_name
        self.state = {"runs": 0, "wickets": 0, "balls_faced": 0, "batting_order": []}
        self.max_iterations = max_iterations
        self.timeout_sec = timeout_sec
        self.api_call_count = 0
        self.max_api_calls = 1000
        self.start_time = time.time()

    def agentic_loop(self, target_runs: int) -> Dict:
        iteration = 0
        while iteration < self.max_iterations:
            # Check timeout
            if time.time() - self.start_time > self.timeout_sec:
                return {"status": "TIMEOUT", "state": self.state, "error": "Exceeded time limit"}

            # Check API limits (prevents cost explosion)
            if self.api_call_count >= self.max_api_calls:
                return {"status": "API_LIMIT_EXCEEDED", "state": self.state}

            # Termination condition
            if self.state["runs"] >= target_runs or self.state["wickets"] >= 10:
                return {"status": "SUCCESS", "state": self.state, "iterations": iteration}

            # Tool calls with tracking
            next_action = self._decide_next_action()
            result = self._execute_tool(next_action)
            self.api_call_count += 1

            # Update state
            self._update_state(result)
            iteration += 1

        return {"status": "MAX_ITERATIONS_REACHED", "state": self.state}

    def _decide_next_action(self) -> str:
        """Reasoning cycle: decide if team should attack, defend, or hold"""
        runs_needed = 180 - self.state["runs"]
        balls_left = 120 - self.state["balls_faced"]

        if runs_needed <= 0:
            return "END_MATCH"
        elif balls_left <= 0:
            return "LOSE_MATCH"
        elif runs_needed / balls_left > 1.5:
            return "AGGRESSIVE_BATTING"
        else:
            return "DEFENSIVE_BATTING"

    def _execute_tool(self, action: str) -> Dict:
        """Simulates tool execution (API call, database query, etc.)"""
        import random
        if action == "AGGRESSIVE_BATTING":
            runs_scored = random.choice([0, 1, 2, 4, 6])
            wicket_lost = 1 if random.random() < 0.15 else 0
        elif action == "DEFENSIVE_BATTING":
            runs_scored = random.choice([0, 1, 1, 2])
            wicket_lost = 1 if random.random() < 0.05 else 0
        else:
            runs_scored = 0
            wicket_lost = 0

        return {"runs": runs_scored, "wicket": wicket_lost}

    def _update_state(self, result: Dict):
        """Update agent state with tool results"""
        self.state["runs"] += result["runs"]
        self.state["wickets"] += result["wicket"]
        self.state["balls_faced"] += 1

# Usage
agent = CricketAgentWithSafeguards("India", max_iterations=50, timeout_sec=10)
final_result = agent.agentic_loop(target_runs=180)
print(f"Result: {final_result}")

# BEST PRACTICE: Synchronous Sequential with checkpointing
from typing import Any, Dict, List

class CricketAgentBestPractice:
    def __init__(self):
        self.state = {}
        self.checkpoints = []

    async def run_sequential_with_checkpoints(self, match_context: Dict[str, Any]) -> Dict[str, Any]:
        """Sequential pattern with state checkpoints—safe and auditable."""
        self.state = match_context.copy()

        # Tool 1: Analyze opposition weakness
        opposition_analysis = await self.analyze_opposition_strength(
            batters=['Rohit', 'Kohli'],
            format='ODI'
        )
        self._checkpoint('opposition_analysis', opposition_analysis)

        # Tool 2: Recommend bowling (depends on Tool 1 output)
        bowling_plan = await self.recommend_bowling_strategy(
            weakness_data=opposition_analysis,
            available_bowlers=['Bumrah', 'Siraj', 'Kuldeep']
        )
        self._checkpoint('bowling_plan', bowling_plan)

        # Tool 3: Finalize field (depends on Tools 1 & 2)
        field_setup = await self.optimize_field_placement(
            bowling_strategy=bowling_plan,
            match_phase=self.state['overs_elapsed']
        )
        self._checkpoint('field_setup', field_setup)

        return {
            'final_strategy': field_setup,
            'checkpoints': self.checkpoints,
            'reasoning_chain': self._reconstruct_reasoning()
        }

    def _checkpoint(self, stage: str, data: Any) -> None:
        """Atomically record intermediate state."""
        self.checkpoints.append({'stage': stage, 'data': data, 'timestamp': __import__('time').time()})

    async def analyze_opposition_strength(self, batters: List[str], format: str) -> Dict:
        # Simulated tool call
        return {'kohli_weakness': 'yorkers', 'rohit_weakness': 'short_balls'}

    async def recommend_bowling_strategy(self, weakness_data: Dict, available_bowlers: List[str]) -> Dict:
        return {'primary_bowler': 'Bumrah', 'strategy': 'yorker_focused'}

    async def optimize_field_placement(self, bowling_strategy: Dict, match_phase: int) -> Dict:
        return {'slip': True, 'gully': True, 'point': False}

    def _reconstruct_reasoning(self) -> str:
        return " -> ".join([cp['stage'] for cp in self.checkpoints])

# ANTI-PATTERN: No state management, tool order ambiguity
class CricketAgentAntiPattern:
    async def run_without_checkpoints(self, match_context: Dict[str, Any]) -> Dict[str, Any]:
        """Dangerous: tools execute without state verification—audit trail lost."""
        # No checkpoints, no state tracking
        bowling = await self.recommend_bowling_strategy(
            weakness_data=None  # BUG: hasn't run opposition analysis yet!
        )
        field = await self.optimize_field_placement(bowling_strategy=bowling)
        # If field setup fails, impossible to debug which tool caused it
        return {'field': field}

    async def recommend_bowling_strategy(self, weakness_data: Dict) -> Dict:
        return {'primary_bowler': 'Unknown'}

    async def optimize_field_placement(self, bowling_strategy: Dict) -> Dict:
        return {'slip': None}

print("Best practice: Synchronous sequential ensures each tool receives complete prior context.")
print("Anti-pattern: Skipping checkpoints makes debugging impossible and breaks tool dependencies.")
